import React from 'react';

const Chatbot = () => {
  const chatbotUrl = 'https://your-chatbot-url.example.com'; // Replace with your actual chatbot URL

  return (
    <div className="container" style={{ padding: '40px 20px' }}>
      <h1>AI Chatbot</h1>
      <p>Use the chatbot to ask questions, get support, or explore project recommendations.</p>
      <div style={{ marginTop: '20px', minHeight: '80vh', border: '1px solid #ddd', borderRadius: '12px', overflow: 'hidden' }}>
        <iframe
          title="AI Chatbot"
          src={chatbotUrl}
          style={{ width: '100%', height: '100%', minHeight: '700px', border: 'none' }}
        />
      </div>
    </div>
  );
};

export default Chatbot;
